checkstyle {
    toolVersion '8.45.1' // Specify a compatible Checkstyle version
    configFile file("${rootDir}/config/checkstyle/checkstyle.xml")
    sourceSets = [project.sourceSets.main]
    checkstyleTest.enabled = false // Disable Checkstyle for test sources if not needed
}

tasks.withType(Checkstyle) {
    reports {
        xml.required = true
        html.required = true
    }
