import android.content.Intent;
import android.os.Bundle;

import androidx.appcompat.app.AppCompatActivity;

import android.view.View;

import androidx.navigation.ui.AppBarConfiguration;

import edu.uiuc.cs427app.databinding.ActivityMainBinding;

import android.widget.Button;

/**
 * The main activity of the application, responsible for displaying a list of cities
 * and handling user interactions to navigate to city details or add new locations.
 */
public class MainActivity extends AppCompatActivity implements View.OnClickListener {

    /**
     * Configuration for the app bar, which includes the navigation drawer.
